{"requests": [{"type": "execute", "stmt": {"sql": "INSERT OR REPLACE INTO \"Game\" (\"id\", \"slug\", \"title\", \"description\", \"coverImage\", \"releaseDate\", \"developer\", \"publisher\", \"platforms\", \"genres\", \"steamAppId\", \"rawgSlug\", \"igdbId\", \"metacriticScore\", \"steamScore\", \"averageScore\", \"createdAt\", \"updatedAt\", \"screenshots\", \"trailerUrl\") VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)", "args": [{"type": "text", "value": "game_motogp26"}, {"type": "text", "value": "motogp-26"}, {"type": "text", "value": "MotoGP 26"}, {"type": "text", "value": "The official MotoGP 2026 game featuring renewed physics, dynamic Riders Ratings, and the full championship roster."}, {"type": "text", "value": "https://cdn.akamai.steamstatic.com/steam/apps/3875050/header.jpg"}, {"type": "text", "value": "2026-04-29"}, {"type": "text", "value": "Milestone"}, {"type": "text", "value": "Milestone"}, {"type": "text", "value": "[\"PC\", \"PlayStation 5\", \"Xbox Series X/S\", \"Nintendo Switch\", \"Nintendo Switch 2\"]"}, {"type": "text", "value": "[\"Racing\", \"Sports\", \"Simulation\"]"}, {"type": "text", "value": "3875050"}, {"type": "null"}, {"type": "null"}, {"type": "null"}, {"type": "null"}, {"type": "null"}, {"type": "text", "value": "2026-04-02T20:30:00.000Z"}, {"type": "text", "value": "2026-04-02T20:30:00.000Z"}, {"type": "text", "value": "[\"https://cdn.akamai.steamstatic.com/steam/apps/3875050/capsule_616x353.jpg\", \"https://cdn.akamai.steamstatic.com/steam/apps/3875050/library_hero.jpg\"]"}, {"type": "null"}]}}, {"type": "execute", "stmt": {"sql": "INSERT OR REPLACE INTO \"Game\" (\"id\", \"slug\", \"title\", \"description\", \"coverImage\", \"releaseDate\", \"developer\", \"publisher\", \"platforms\", \"genres\", \"steamAppId\", \"rawgSlug\", \"igdbId\", \"metacriticScore\", \"steamScore\", \"averageScore\", \"createdAt\", \"updatedAt\", \"screenshots\", \"trailerUrl\") VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)", "args": [{"type": "text", "value": "game_mouse_pi"}, {"type": "text", "value": "mouse-pi-for-hire"}, {"type": "text", "value": "MOUSE: P.I. For Hire"}, {"type": "text", "value": "A noir first-person shooter with hand-drawn 1930s rubber hose animation. Play as detective Jack Pepper in the seedy underworld of Mouseburg."}, {"type": "text", "value": "https://cdn.akamai.steamstatic.com/steam/apps/2416450/header.jpg"}, {"type": "text", "value": "2026-04-16"}, {"type": "text", "value": "Fumi Games"}, {"type": "text", "value": "PlaySide Studios"}, {"type": "text", "value": "[\"PC\", \"PlayStation 5\", \"Xbox Series X/S\", \"Nintendo Switch 2\"]"}, {"type": "text", "value": "[\"FPS\", \"Action\", \"Indie\"]"}, {"type": "text", "value": "2416450"}, {"type": "null"}, {"type": "null"}, {"type": "null"}, {"type": "null"}, {"type": "null"}, {"type": "text", "value": "2026-04-02T20:30:00.000Z"}, {"type": "text", "value": "2026-04-02T20:30:00.000Z"}, {"type": "text", "value": "[\"https://cdn.akamai.steamstatic.com/steam/apps/2416450/capsule_616x353.jpg\", \"https://cdn.akamai.steamstatic.com/steam/apps/2416450/library_hero.jpg\"]"}, {"type": "text", "value": "https://www.youtube.com/watch?v=CzeInmapu-Y"}]}}, {"type": "execute", "stmt": {"sql": "INSERT OR REPLACE INTO \"Game\" (\"id\", \"slug\", \"title\", \"description\", \"coverImage\", \"releaseDate\", \"developer\", \"publisher\", \"platforms\", \"genres\", \"steamAppId\", \"rawgSlug\", \"igdbId\", \"metacriticScore\", \"steamScore\", \"averageScore\", \"createdAt\", \"updatedAt\", \"screenshots\", \"trailerUrl\") VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)", "args": [{"type": "text", "value": "game_narin"}, {"type": "text", "value": "narin-the-orange-room"}, {"type": "text", "value": "Narin: The Orange Room"}, {"type": "text", "value": "A supernatural school horror game set in South Korea where a student must survive terrifying encounters in an abandoned school."}, {"type": "text", "value": "https://cdn.akamai.steamstatic.com/steam/apps/2050710/header.jpg"}, {"type": "text", "value": "2026-04-07"}, {"type": "text", "value": "Redsensation Games"}, {"type": "text", "value": "Redsensation Games"}, {"type": "text", "value": "[\"PC\"]"}, {"type": "text", "value": "[\"Horror\", \"Adventure\", \"Indie\"]"}, {"type": "text", "value": "2050710"}, {"type": "null"}, {"type": "null"}, {"type": "null"}, {"type": "null"}, {"type": "null"}, {"type": "text", "value": "2026-04-02T20:30:00.000Z"}, {"type": "text", "value": "2026-04-02T20:30:00.000Z"}, {"type": "text", "value": "[\"https://cdn.akamai.steamstatic.com/steam/apps/2050710/capsule_616x353.jpg\", \"https://cdn.akamai.steamstatic.com/steam/apps/2050710/library_hero.jpg\"]"}, {"type": "null"}]}}, {"type": "execute", "stmt": {"sql": "INSERT OR REPLACE INTO \"Article\" (\"id\", \"slug\", \"title\", \"content\", \"summary\", \"imageUrl\", \"sourceUrl\", \"sourceName\", \"category\", \"tags\", \"gameId\", \"status\", \"publishedAt\", \"sourcePublishedAt\", \"pipelineRunId\", \"createdAt\", \"updatedAt\") VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)", "args": [{"type": "text", "value": "art_20260402b_mg01"}, {"type": "text", "value": "motogp-26-new-physics-career-mode-april-29"}, {"type": "text", "value": "MotoGP 26 Revamps Physics and Career Mode Ahead of April 29 Launch"}, {"type": "text", "value": "<p>Milestone has officially unveiled <strong>MotoGP 26</strong>, the latest entry in its long-running motorcycle racing franchise, confirming an April 29 release date across PS5, Xbox Series X|S, Nintendo Switch, Nintendo Switch 2, and PC. This year's installment promises the most significant overhaul the series has seen in years.</p>\n\n<p>The headline feature is a completely rebuilt physics system centered on a new rider-based handling model. Rather than simply steering the bike, players now manage weight transfer, body positioning, and throttle control independently \u2014 a design choice Milestone says will reward skilled riders with far more nuanced feedback on every corner entry and exit.</p>\n\n<img src=\"https://cdn.akamai.steamstatic.com/steam/apps/3875050/capsule_616x353.jpg\" alt=\"MotoGP 26 racing gameplay\" />\n\n<p>Career mode has also been redesigned from the ground up. A new progression system tracks your rider's reputation across the paddock, and real-world race results dynamically update Rider Ratings throughout the season. If Marc M\u00e1rquez has a dominant weekend at Mugello, his in-game stats adjust to reflect that performance \u2014 a feature that keeps career mode feeling fresh well beyond launch week.</p>\n\n<p>The full 2026 MotoGP Championship is included, with all official riders, teams, bikes, and tracks. Milestone has also confirmed expanded customization options for liveries and gear, along with improvements to online multiplayer stability.</p>\n\n<img src=\"https://cdn.akamai.steamstatic.com/steam/apps/3875050/library_hero.jpg\" alt=\"MotoGP 26 key art\" />\n\n<p>MotoGP 26 will be available on Steam, the Microsoft Store, and the Epic Games Store on PC, alongside console versions. Nintendo Switch 2 support at launch is a notable addition, making this the first MotoGP title to ship on Nintendo's new hardware from day one.</p>"}, {"type": "text", "value": "Milestone's MotoGP 26 features rebuilt physics, dynamic Rider Ratings, and launches April 29 on all major platforms including Switch 2."}, {"type": "text", "value": "https://cdn.akamai.steamstatic.com/steam/apps/3875050/header.jpg"}, {"type": "null"}, {"type": "null"}, {"type": "text", "value": "news"}, {"type": "text", "value": "[\"Racing\", \"MotoGP\", \"Milestone\", \"April 2026\", \"Switch 2\"]"}, {"type": "text", "value": "game_motogp26"}, {"type": "text", "value": "published"}, {"type": "text", "value": "2026-04-02T20:30:00.000Z"}, {"type": "null"}, {"type": "null"}, {"type": "text", "value": "2026-04-02T20:30:00.000Z"}, {"type": "text", "value": "2026-04-02T20:30:00.000Z"}]}}, {"type": "execute", "stmt": {"sql": "INSERT OR REPLACE INTO \"Article\" (\"id\", \"slug\", \"title\", \"content\", \"summary\", \"imageUrl\", \"sourceUrl\", \"sourceName\", \"category\", \"tags\", \"gameId\", \"status\", \"publishedAt\", \"sourcePublishedAt\", \"pipelineRunId\", \"createdAt\", \"updatedAt\") VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)", "args": [{"type": "text", "value": "art_20260402b_ms01"}, {"type": "text", "value": "mouse-pi-for-hire-retro-fps-launches-april-16"}, {"type": "text", "value": "MOUSE: P.I. For Hire Brings 1930s Cartoon Noir to FPS Genre on April 16"}, {"type": "text", "value": "<p>The wait is nearly over for one of 2026's most visually distinctive shooters. <strong>MOUSE: P.I. For Hire</strong>, the hand-drawn first-person shooter from Fumi Games and PlaySide Studios, launches on April 16 across PlayStation 5, Xbox Series X|S, Nintendo Switch 2, and PC via Steam.</p>\n\n<p>Originally slated for a March 19 release, the studio delayed the game by a month to give it additional polish. \"We want every frame of this game to feel like stepping into a lost cartoon reel,\" the developers said in a statement. Based on preview coverage, the extra time appears well spent.</p>\n\n<img src=\"https://cdn.akamai.steamstatic.com/steam/apps/2416450/capsule_616x353.jpg\" alt=\"MOUSE: P.I. For Hire gameplay showing 1930s cartoon art style\" />\n\n<p>Players take on the role of Jack Pepper, a hardboiled mouse detective voiced by Troy Baker, navigating the corrupt streets of Mouseburg. What begins as a routine missing persons case quickly spirals into a web of kidnapping, corruption, and murder. The game blends classic boomer-shooter gunplay with investigation sequences where players gather clues and interrogate quirky NPCs.</p>\n\n<p>The rubber hose animation style \u2014 drawn entirely by hand, frame by frame \u2014 sets MOUSE apart from anything else on the market. Every enemy, environment, and explosion channels the look of 1930s theatrical cartoons, all rendered in striking black and white with selective color accents. The jazz-infused soundtrack, featuring a collaboration with French electro-swing band Caravan Palace, completes the atmosphere.</p>\n\n<img src=\"https://cdn.akamai.steamstatic.com/steam/apps/2416450/library_hero.jpg\" alt=\"MOUSE: P.I. For Hire key art featuring Jack Pepper\" />\n\n<p>MOUSE: P.I. For Hire is priced at $29.99, with a Digital Deluxe Edition at $39.99 that includes access to the first DLC expansion and the full original soundtrack. Preview impressions have called it \"the most original FPS in years,\" and the game is expected to run 12 to 20 hours.</p>"}, {"type": "text", "value": "Fumi Games' hand-drawn 1930s noir FPS launches April 16 on PS5, Xbox, Switch 2, and PC, featuring Troy Baker as detective Jack Pepper."}, {"type": "text", "value": "https://cdn.akamai.steamstatic.com/steam/apps/2416450/header.jpg"}, {"type": "null"}, {"type": "null"}, {"type": "text", "value": "news"}, {"type": "text", "value": "[\"FPS\", \"Indie\", \"MOUSE\", \"April 2026\", \"Troy Baker\"]"}, {"type": "text", "value": "game_mouse_pi"}, {"type": "text", "value": "published"}, {"type": "text", "value": "2026-04-02T20:30:00.000Z"}, {"type": "null"}, {"type": "null"}, {"type": "text", "value": "2026-04-02T20:30:00.000Z"}, {"type": "text", "value": "2026-04-02T20:30:00.000Z"}]}}, {"type": "execute", "stmt": {"sql": "INSERT OR REPLACE INTO \"Article\" (\"id\", \"slug\", \"title\", \"content\", \"summary\", \"imageUrl\", \"sourceUrl\", \"sourceName\", \"category\", \"tags\", \"gameId\", \"status\", \"publishedAt\", \"sourcePublishedAt\", \"pipelineRunId\", \"createdAt\", \"updatedAt\") VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)", "args": [{"type": "text", "value": "art_20260402b_nr01"}, {"type": "text", "value": "narin-the-orange-room-horror-steam-april-7"}, {"type": "text", "value": "Narin: The Orange Room Brings Supernatural School Horror to Steam on April 7"}, {"type": "text", "value": "<p>Korean indie studio Redsensation Games is preparing to launch <strong>Narin: The Orange Room</strong> on Steam on April 7, bringing a deeply unsettling supernatural horror experience set inside an abandoned South Korean school. Priced at $14.99, the game has been quietly building buzz since its demo left a strong impression during Steam Next Fest.</p>\n\n<p>The story follows a student who awakens in a decrepit school building with no memory of how they arrived. The titular Orange Room serves as both a sanctuary and a puzzle hub \u2014 a single safe space in a building crawling with hostile entities drawn from Korean folklore and urban legend. Exploration is tense and methodical, with limited resources forcing players to think carefully about when to hide and when to run.</p>\n\n<img src=\"https://cdn.akamai.steamstatic.com/steam/apps/2050710/capsule_616x353.jpg\" alt=\"Narin: The Orange Room horror gameplay\" />\n\n<p>What distinguishes Narin from the crowded indie horror field is its cultural specificity. The school setting draws from real architectural details of Korean educational buildings, and the supernatural threats are rooted in Korean ghost stories rather than Western horror tropes. The result is an atmosphere that feels genuinely unfamiliar \u2014 and therefore far more frightening \u2014 for international audiences.</p>\n\n<p>Redsensation has confirmed the game runs approximately six to eight hours on a first playthrough, with multiple endings that encourage replay. The demo's sound design was singled out by players as particularly effective, using spatial audio to create constant unease even in seemingly empty hallways.</p>\n\n<img src=\"https://cdn.akamai.steamstatic.com/steam/apps/2050710/library_hero.jpg\" alt=\"Narin: The Orange Room key art\" />\n\n<p>Narin: The Orange Room launches exclusively on PC via Steam on April 7. Console ports have not yet been announced, though the developer has hinted at future platform expansion if the launch goes well.</p>"}, {"type": "text", "value": "Korean indie horror game Narin: The Orange Room launches on Steam April 7 at $14.99, offering supernatural scares rooted in Korean folklore."}, {"type": "text", "value": "https://cdn.akamai.steamstatic.com/steam/apps/2050710/header.jpg"}, {"type": "null"}, {"type": "null"}, {"type": "text", "value": "news"}, {"type": "text", "value": "[\"Horror\", \"Indie\", \"Steam\", \"April 2026\", \"Korean Horror\"]"}, {"type": "text", "value": "game_narin"}, {"type": "text", "value": "published"}, {"type": "text", "value": "2026-04-02T20:30:00.000Z"}, {"type": "null"}, {"type": "null"}, {"type": "text", "value": "2026-04-02T20:30:00.000Z"}, {"type": "text", "value": "2026-04-02T20:30:00.000Z"}]}}, {"type": "execute", "stmt": {"sql": "INSERT OR REPLACE INTO \"Article\" (\"id\", \"slug\", \"title\", \"content\", \"summary\", \"imageUrl\", \"sourceUrl\", \"sourceName\", \"category\", \"tags\", \"gameId\", \"status\", \"publishedAt\", \"sourcePublishedAt\", \"pipelineRunId\", \"createdAt\", \"updatedAt\") VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)", "args": [{"type": "text", "value": "art_20260402b_nte1"}, {"type": "text", "value": "nte-neverness-to-everness-cross-platform-mobile-launch-april-29"}, {"type": "text", "value": "Neverness to Everness Launches April 29 Across PC, PS5, and Mobile With Full Cross-Play"}, {"type": "text", "value": "<p>Hotta Studio, the team behind Tower of Fantasy, is preparing to launch its ambitious new open-world RPG <strong>NTE: Neverness to Everness</strong> on April 29 across PC, PlayStation 5, iOS, Android, and Mac \u2014 all with full cross-platform support from day one.</p>\n\n<p>Set in the modern city of Hethereau, NTE drops players into a world where supernatural anomalies have become part of everyday life. As an Appraiser \u2014 a specialist in cataloging and confronting these anomalies \u2014 players explore a dense urban open world filled with hidden encounters, faction conflicts, and environmental storytelling. The hack-and-slash combat draws comparisons to Genshin Impact, but NTE leans harder into a contemporary urban setting rather than fantasy landscapes.</p>\n\n<p>The mobile version is not a compromised port. Hotta Studio has designed the game for mobile parity from the start, with touch-optimized controls, scalable graphics, and cross-progression across every platform. Progress made on your phone carries seamlessly to your PS5 or PC session and back \u2014 a feature that could make NTE a daily-driver for commuters and couch gamers alike.</p>\n\n<p>NTE is free-to-play with a gacha-style character acquisition system, following the model established by Tower of Fantasy and other live-service RPGs in the genre. The Co-Ex Test, a limited beta that ran on PC and PS5, received positive feedback for its combat fluidity and world design, though some testers flagged the monetization structure as aggressive.</p>\n\n<p>Pre-registration is now open on the App Store and Google Play. Hotta Studio has promised launch-window events, free character rewards, and a roadmap of post-launch content through the end of 2026.</p>"}, {"type": "text", "value": "Hotta Studio's NTE: Neverness to Everness launches free-to-play on April 29 across PC, PS5, mobile, and Mac with full cross-platform play."}, {"type": "null"}, {"type": "null"}, {"type": "null"}, {"type": "text", "value": "mobile"}, {"type": "text", "value": "[\"Mobile\", \"RPG\", \"Free-to-Play\", \"Cross-Platform\", \"April 2026\"]"}, {"type": "null"}, {"type": "text", "value": "published"}, {"type": "text", "value": "2026-04-02T20:30:00.000Z"}, {"type": "null"}, {"type": "null"}, {"type": "text", "value": "2026-04-02T20:30:00.000Z"}, {"type": "text", "value": "2026-04-02T20:30:00.000Z"}]}}, {"type": "execute", "stmt": {"sql": "INSERT OR REPLACE INTO \"Article\" (\"id\", \"slug\", \"title\", \"content\", \"summary\", \"imageUrl\", \"sourceUrl\", \"sourceName\", \"category\", \"tags\", \"gameId\", \"status\", \"publishedAt\", \"sourcePublishedAt\", \"pipelineRunId\", \"createdAt\", \"updatedAt\") VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)", "args": [{"type": "text", "value": "art_20260402b_pk01"}, {"type": "text", "value": "pokemon-champions-switch-launch-april-8-competitive-battles"}, {"type": "text", "value": "Pok\u00e9mon Champions Launches April 8 as the Series' First Dedicated Competitive Battle Game"}, {"type": "text", "value": "<p>The Pok\u00e9mon Company has confirmed that <strong>Pok\u00e9mon Champions</strong> will launch on Nintendo Switch on April 8, 2026, marking a significant new direction for the franchise. Unlike mainline entries that balance exploration, story, and collecting, Champions is built from the ground up as a pure competitive battling platform.</p>\n\n<p>Champions strips away the RPG framework entirely. Players can immediately build and customize their ideal teams, setting natures, abilities, EVs, and movesets without the hours of breeding and training that competitive play has traditionally required. It is a free-to-start download \u2014 the base game is free with limited features, while a full unlock is available for purchase.</p>\n\n<p>The game supports the full roster of Pok\u00e9mon available through Pok\u00e9mon HOME transfers, including Mega Evolutions from Pok\u00e9mon Legends: Z-A. Players who transfer Chesnaught, Delphox, Greninja, or Eternal Flower Floette from Legends: Z-A via HOME will receive their respective Mega Stones. The Pok\u00e9mon Company has also revealed new Mega Evolutions for Meganium, Emboar, and Feraligatr exclusive to Champions.</p>\n\n<p>The competitive infrastructure is robust: ranked ladders, automated tournaments, spectator mode, and full integration with the official Play! Pok\u00e9mon Championship Series. Beginning in April, official competitive events will transition from Scarlet and Violet to Champions as the standard tournament platform.</p>\n\n<p>A free Nintendo Switch 2 update will deliver enhanced graphics when Nintendo's new hardware launches. A mobile version for iOS and Android is expected later in 2026, with cross-platform play between Switch and mobile confirmed. Early downloaders will receive a bonus Dragonite via in-game mail.</p>"}, {"type": "text", "value": "Pok\u00e9mon Champions, the series' first dedicated competitive battle game, launches free-to-start on Switch April 8 with Switch 2 and mobile versions coming later."}, {"type": "null"}, {"type": "null"}, {"type": "null"}, {"type": "text", "value": "news"}, {"type": "text", "value": "[\"Pokemon\", \"Nintendo Switch\", \"Competitive\", \"April 2026\", \"Free-to-Play\"]"}, {"type": "null"}, {"type": "text", "value": "published"}, {"type": "text", "value": "2026-04-02T20:30:00.000Z"}, {"type": "null"}, {"type": "null"}, {"type": "text", "value": "2026-04-02T20:30:00.000Z"}, {"type": "text", "value": "2026-04-02T20:30:00.000Z"}]}}, {"type": "execute", "stmt": {"sql": "INSERT OR REPLACE INTO \"Review\" (\"id\", \"slug\", \"gameId\", \"title\", \"content\", \"score\", \"pros\", \"cons\", \"sourceReviews\", \"verdict\", \"status\", \"publishedAt\", \"pipelineRunId\", \"createdAt\", \"updatedAt\") VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)", "args": [{"type": "text", "value": "rev_20260402b_ms01"}, {"type": "text", "value": "mouse-pi-for-hire-review-retro-fps-masterpiece"}, {"type": "text", "value": "game_mouse_pi"}, {"type": "text", "value": "MOUSE: P.I. For Hire Review \u2014 A Cartoon Noir Masterclass"}, {"type": "text", "value": "<p>There is nothing else that looks like MOUSE: P.I. For Hire. Fumi Games has spent years painstakingly hand-drawing every frame of this first-person shooter in the rubber hose animation style of 1930s theatrical cartoons, and the result is a game that feels less like playing a shooter and more like inhabiting a lost piece of animation history. But MOUSE is far more than a visual novelty \u2014 beneath the ink-and-cel aesthetic beats the heart of a genuinely excellent boomer shooter with surprisingly sharp detective mechanics.</p>\n\n<img src=\"https://cdn.akamai.steamstatic.com/steam/apps/2416450/capsule_616x353.jpg\" alt=\"MOUSE: P.I. For Hire combat gameplay showing cartoon-style action\" />\n\n<p>You play as Jack Pepper, a former war hero turned private investigator in the fictional city of Mouseburg. Troy Baker delivers one of his most entertaining performances as Pepper \u2014 world-weary, sardonic, and perpetually one wisecrack away from getting punched. When a routine missing persons case leads Pepper into the city's criminal underground, the noir narrative unfolds with genuine twists that kept me guessing through the 15-hour campaign. The supporting cast is equally memorable: a lounge-singing femme fatale, a crooked police chief with a glass eye, and a rival detective who might be the most insufferable character in gaming this year \u2014 in the best possible way.</p>\n\n<p>The shooting mechanics are tight and responsive, channeling the best of the modern retro-FPS renaissance while carving out an identity entirely its own. Pepper's arsenal includes revolvers, tommy guns, shotguns, and an array of cartoon-inspired experimental weapons that defy physics in the best possible way. A boxing glove gun sends enemies ragdolling across rooms in exaggerated arcs. A portable hole can be placed on walls to create new pathways or on floors to drop enemies into the void below. An anvil launcher does exactly what you'd expect, and it never stops being satisfying. The weapon variety encourages constant experimentation, and the game rewards creative play with style bonuses that feed into an upgrade system allowing you to enhance Pepper's movement and combat abilities.</p>\n\n<img src=\"https://cdn.akamai.steamstatic.com/steam/apps/2416450/library_hero.jpg\" alt=\"MOUSE: P.I. For Hire investigation sequence in Mouseburg\" />\n\n<p>Level design deserves special praise. Each chapter takes place in a distinct Mouseburg location \u2014 a smoky jazz club, a waterfront warehouse stacked with contraband, a corrupt mayor's mansion dripping with gilded excess \u2014 and every environment is dense with secrets, alternate routes, and environmental storytelling. The hand-drawn art means every room feels curated rather than procedurally assembled, and the designers exploit the cartoon aesthetic to create impossible spaces that somehow feel internally consistent. Stairways loop back on themselves like Escher drawings. Doors open into rooms that shouldn't physically fit inside the buildings that contain them. It is level design that could only exist in a cartoon, and Fumi Games leans into that freedom with infectious enthusiasm.</p>\n\n<p>Between combat chapters, investigation sequences slow the pace beautifully and provide welcome breathing room. Pepper examines crime scenes, collects physical evidence, photographs key details, and interrogates suspects in dialogue trees that actually affect how later levels play out. Accuse the wrong person, and you might face an ambush you could have avoided. Find a hidden clue, and a shortcut opens in the next combat level. Miss a piece of evidence entirely, and an optional boss encounter becomes mandatory. These aren't just narrative window dressing \u2014 they meaningfully alter gameplay in ways that reward attentive players and encourage multiple playthroughs.</p>\n\n<iframe width=\"560\" height=\"315\" src=\"https://www.youtube.com/embed/CzeInmapu-Y\" title=\"MOUSE: P.I. For Hire Official Gameplay Trailer\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture\" allowfullscreen></iframe>\n\n<p>The jazz soundtrack, featuring an original collaboration with French electro-swing band Caravan Palace, is phenomenal and deserves to be recognized as one of the year's best game scores. Tracks shift dynamically between moody investigation themes built around solo piano and muted trumpet, and frenetic combat arrangements that layer in driving drums, blaring horns, and distorted bass. The transition between exploration and combat is seamless, and the music is so good that the $39.99 Deluxe Edition's included OST feels like genuine added value rather than filler padding.</p>\n\n<p>If there are weaknesses, they're minor but worth mentioning. Some boss fights rely too heavily on pattern memorization rather than the creative improvisation that makes standard encounters so enjoyable. The final chapter's difficulty spike feels slightly at odds with the otherwise smooth difficulty curve, introducing enemy types that punish the aggressive playstyle the game spent twelve chapters encouraging. The game also locks its PS4 and Xbox One versions behind a later release date, which may frustrate players on older hardware who have been following development.</p>\n\n<img src=\"https://cdn.akamai.steamstatic.com/steam/apps/2416450/header.jpg\" alt=\"MOUSE: P.I. For Hire title screen and key art\" />\n\n<p>But these are small complaints against a game that delivers on virtually every front. MOUSE: P.I. For Hire is the rare title where the art style is not a gimmick but an integral part of the design philosophy \u2014 the cartoon logic that governs the visuals also governs the level design, the weapons, the humor, and even the narrative structure. It is a complete creative vision executed with extraordinary craft and genuine love for both its animation influences and its shooter heritage. In a genre increasingly crowded with retro-styled shooters, MOUSE stands alone as something truly original, and it sets a new bar for what indie studios can achieve when ambition meets execution.</p>"}, {"type": "float", "value": 8.5}, {"type": "text", "value": "[\"Stunning hand-drawn 1930s animation style unlike anything else\", \"Tight, responsive gunplay with creative cartoon weapons\", \"Excellent level design with meaningful secrets and alternate paths\", \"Troy Baker delivers a standout voice performance\", \"Investigation sequences add genuine variety and player agency\", \"Outstanding jazz soundtrack with Caravan Palace collaboration\"]"}, {"type": "text", "value": "[\"Some boss fights lean too heavily on pattern memorization\", \"Final chapter difficulty spike feels slightly uneven\", \"PS4 and Xbox One versions delayed to a later date\"]"}, {"type": "text", "value": "[]"}, {"type": "text", "value": "MOUSE: P.I. For Hire is a stunning achievement in both art direction and game design. Its hand-drawn 1930s aesthetic is not merely cosmetic \u2014 it informs every aspect of the gameplay, from the cartoon-logic weapons to the impossible architecture of its meticulously crafted levels. Combined with sharp shooting mechanics, genuinely engaging detective sequences, and Troy Baker's charismatic lead performance, this is one of 2026's must-play shooters."}, {"type": "text", "value": "published"}, {"type": "text", "value": "2026-04-02T20:30:00.000Z"}, {"type": "null"}, {"type": "text", "value": "2026-04-02T20:30:00.000Z"}, {"type": "text", "value": "2026-04-02T20:30:00.000Z"}]}}]}
ENDJSON

